import{_ as i,o as t,c as a,a2 as r}from"./chunks/framework.Cuq8tsM6.js";const u=JSON.parse('{"title":"Dedicated Email","description":"","frontmatter":{"title":"Dedicated Email"},"headers":[],"relativePath":"docs/fr/advertisers/dedicated-email/index.md","filePath":"docs/fr/advertisers/dedicated-email/index.md"}'),d={name:"docs/fr/advertisers/dedicated-email/index.md"};function n(o,e,s,p,l,c){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="emailing-dedie-dedicated-newsletter" tabindex="-1">Emailing Dédié (Dedicated Newsletter) <a class="header-anchor" href="#emailing-dedie-dedicated-newsletter" aria-label="Permalink to &quot;Emailing Dédié (Dedicated Newsletter)&quot;">​</a></h1><p>Profitez de la puissance de la recommandation (Endorsement) en prenant la parole auprès de la base d&#39;abonnés de nos partenaires.</p><div><a href="https://app.getinside.media/" target="_blank" class="btn btn-primary mr-2">Accéder au SaaS</a><a href="1-brief-annonceur" class="btn btn-outline">Voir le process</a></div><hr><div style="background:var(--gi-tint-blue-bg);border:1px solid var(--gi-accent);border-radius:8px;padding:24px;margin-bottom:40px;"><h2>🤝 Le concept : l&#39;Endorsement</h2><p>Contrairement à l&#39;achat de base classique, nous privilégions ici une approche de <strong>recommandation</strong>.</p><p>C&#39;est le Distributeur qui s&#39;adresse à sa communauté pour lui présenter votre offre comme un &quot;privilège abonné&quot;. Cela garantit de meilleurs taux d&#39;ouverture et une confiance accrue.</p></div><h2>Les 3 Scénarios d&#39;Activation</h2><p>Choisissez le moment idéal pour toucher votre cible.</p><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(250px, 1fr));gap:20px;margin-bottom:40px;width:100%;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3>📢 Blast (Newsletter)</h3><p>Envoi massif sur tout ou partie de la base opt-in du distributeur.</p><div style="display:flex;gap:10px;margin-top:15px;"><span style="background:var(--gi-tint-blue-bg);color:var(--gi-accent);padding:4px 8px;border-radius:4px;font-size:12px;font-weight:bold;">Volume</span><span style="background:var(--gi-tint-blue-bg);color:var(--gi-accent);padding:4px 8px;border-radius:4px;font-size:12px;font-weight:bold;">Notoriété</span></div></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3>🛍️ Post-Purchase</h3><p>Email envoyé automatiquement juste après une commande.</p><div style="display:flex;gap:10px;margin-top:15px;"><span style="background:var(--gi-tint-purple-bg);color:var(--gi-tint-purple-text);padding:4px 8px;border-radius:4px;font-size:12px;font-weight:bold;">Taux d&#39;ouverture max</span><span style="background:var(--gi-tint-purple-bg);color:var(--gi-tint-purple-text);padding:4px 8px;border-radius:4px;font-size:12px;font-weight:bold;">Hot Prospect</span></div></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3>👋 Welcome Pack</h3><p>Intégration dans la séquence de bienvenue des nouveaux inscrits.</p><div style="display:flex;gap:10px;margin-top:15px;"><span style="background:var(--gi-tint-green-bg);color:var(--gi-tint-green-text);padding:4px 8px;border-radius:4px;font-size:12px;font-weight:bold;">Attention</span><span style="background:var(--gi-tint-green-bg);color:var(--gi-tint-green-text);padding:4px 8px;border-radius:4px;font-size:12px;font-weight:bold;">Engagement</span></div></div></div><h2>Le flux de production (Workflow)</h2><div style="display:flex;flex-direction:column;gap:15px;margin-bottom:40px;"><a href="1-brief-annonceur" style="text-decoration:none;color:inherit;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;transition:background 0.2s;" class="gi-tile"><div style="font-size:24px;width:40px;text-align:center;">1</div><div><strong class="d-block">Le Brief Annonceur</strong><span>Vous définissez l&#39;offre et fournissez les assets via notre formulaire.</span></div><div style="margin-left:auto;color:var(--vp-c-text-3);">➝</div></div></a><a href="2-creation-distributeur" style="text-decoration:none;color:inherit;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;transition:background 0.2s;" class="gi-tile"><div style="font-size:24px;width:40px;text-align:center;">2</div><div><strong class="d-block">Création (Distributeur)</strong><span>Le distributeur conçoit l&#39;email en respectant sa charte (ou délègue au Studio).</span></div><div style="margin-left:auto;color:var(--vp-c-text-3);">➝</div></div></a><a href="3-validation-diffusion" style="text-decoration:none;color:inherit;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;transition:background 0.2s;" class="gi-tile"><div style="font-size:24px;width:40px;text-align:center;">3</div><div><strong class="d-block">Validation &amp; Diffusion</strong><span>Intégration du tracking, double validation (BAT) et envoi final.</span></div><div style="margin-left:auto;color:var(--vp-c-text-3);">➝</div></div></a></div><h2>Pourquoi passer par getinside ?</h2><div style="display:flex;flex-direction:column;gap:20px;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">💎</div><div><h3>Inventaire Premium</h3><p>Accédez à des bases de données ultra-qualifiées (+250 e-commerçants) que vous ne trouverez pas sur les plateformes d&#39;affiliation classiques.</p></div></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">🎯</div><div><h3>Ciblage Contextuel</h3><p>Associez votre image à une marque affinitaire. Le taux de réactivité est bien supérieur à de l&#39;emailing de conquête froid (Cold Emailing).</p></div></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">🛡️</div><div><h3>Sécurité &amp; Tracking</h3><p>Nous sécurisons les fonds, validons la qualité technique (Délivrabilité, Responsive) et gérons les redirections de tracking pour vous.</p></div></div></div>',12)])])}const g=i(d,[["render",n]]);export{u as __pageData,g as default};
